import React, { useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { PRODUCTS, CATEGORIES } from '../data/products';
import { ArrowLeft } from 'lucide-react';
import { useLanguage } from '../LanguageContext';

const ProductList: React.FC = () => {
  const { categoryId } = useParams<{ categoryId: string }>();
  const { t, language } = useLanguage();

  const category = CATEGORIES.find(c => c.id === categoryId);
  const products = PRODUCTS.filter(p => p.categoryId === categoryId);

  useEffect(() => {
    if (category) {
      document.title = `${language === 'hi' && category.title_hi ? category.title_hi : category.title} | Shree G Hinges`;
    }
  }, [category, language]);

  if (!category) {
    return <div className="p-12 text-center text-gray-500">{t('product.categoryNotFound')}</div>;
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-8">
          <Link to="/products" className="inline-flex items-center text-gray-500 hover:text-brand-blue mb-4">
            <ArrowLeft size={16} className="mr-2" /> {t('product.backToCategories')}
          </Link>
          <h1 className="text-3xl font-bold text-brand-blue">
            {language === 'hi' && category.title_hi ? category.title_hi : category.title}
          </h1>
          <p className="text-gray-600 mt-2">
            {language === 'hi' && category.description_hi ? category.description_hi : category.description}
          </p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {products.map((product) => {
            const mainSpec = product.variants[0];
            return (
              <Link 
                key={product.id} 
                to={`/products/${categoryId}/${product.id}`}
                className="bg-white rounded-lg shadow-sm hover:shadow-md transition-all p-4 group"
              >
                <div className="bg-gray-100 rounded-md aspect-square overflow-hidden mb-4 p-4 flex items-center justify-center">
                  <img 
                    src={product.imageUrl} 
                    alt={product.name} 
                    className="max-w-full max-h-full object-contain mix-blend-multiply group-hover:scale-105 transition-transform"
                  />
                </div>
                <h3 className="font-bold text-gray-900 group-hover:text-brand-blue">
                  {language === 'hi' && product.name_hi ? product.name_hi : product.name}
                </h3>
                {mainSpec && (
                  <p className="text-xs text-gray-500 mt-1">{t('product.itemCode')}: {mainSpec.itemCode || 'N/A'}</p>
                )}
                {product.variants.length > 1 && (
                   <span className="text-[10px] bg-brand-yellow/20 text-brand-blue px-2 py-0.5 rounded-full mt-1 inline-block">
                     {product.variants.length} {t('product.variantsCount')}
                   </span>
                )}
                <div className="mt-3 text-sm font-medium text-brand-yellow">{t('home.viewSpecs')} &rarr;</div>
              </Link>
            );
          })}
        </div>

        {products.length === 0 && (
          <div className="text-center py-20 bg-white rounded-lg border-2 border-dashed border-gray-200">
            <p className="text-gray-500">{t('product.noProducts')}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProductList;

import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { PRODUCTS } from '../data/products';
import { ArrowLeft, Download, Share2 } from 'lucide-react';
import { useLanguage } from '../LanguageContext';

const ProductDetail: React.FC = () => {
  const { productId } = useParams<{ productId: string }>();
  const { t, language } = useLanguage();
  const product = PRODUCTS.find(p => p.id === productId);

  // State for image gallery
  const [selectedImage, setSelectedImage] = useState<string>('');

  // Initialize selected image when product loads
  useEffect(() => {
    if (product) {
      setSelectedImage(product.imageUrl);
      document.title = `${language === 'hi' && product.name_hi ? product.name_hi : product.name} | Shree G Hinges`;
    }
  }, [product, language]);

  if (!product) {
    return <div className="p-12 text-center text-gray-500">{t('product.notFound')}</div>;
  }

  // Get all images available for the product
  const productImages = product.images && product.images.length > 0 
    ? product.images 
    : [product.imageUrl];

  return (
    <div className="min-h-screen bg-white py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* Breadcrumb / Back */}
        <div className="mb-8 flex justify-between items-center">
          <Link to={`/products/${product.categoryId}`} className="inline-flex items-center text-gray-500 hover:text-brand-blue transition-colors">
            <ArrowLeft size={20} className="mr-2" /> {t('product.backToList')}
          </Link>
        </div>

        <div className="flex flex-col lg:flex-row gap-12 lg:gap-16 items-start">

          {/* LEFT SIDE: Image Gallery */}
          <div className="w-full lg:w-1/2">
            {/* Main Image Display */}
            <div className="bg-gray-50 rounded-2xl border border-gray-100 overflow-hidden p-8 flex items-center justify-center shadow-inner mb-4 h-[400px]">
              <img 
                src={selectedImage} 
                alt={product.name} 
                className="w-full h-full object-contain mix-blend-multiply transition-transform duration-500"
                onError={(e) => {
                  e.currentTarget.src = 'https://via.placeholder.com/500x500?text=Image+Not+Found';
                }}
              />
            </div>

            {/* Thumbnails */}
            {productImages.length > 1 && (
              <div className="flex gap-4 overflow-x-auto pb-2">
                {productImages.map((img, index) => (
                  <button 
                    key={index}
                    onClick={() => setSelectedImage(img)}
                    className={`relative w-24 h-24 flex-shrink-0 bg-gray-50 rounded-lg border-2 overflow-hidden flex items-center justify-center p-2 ${selectedImage === img ? 'border-brand-yellow ring-2 ring-brand-yellow/20' : 'border-gray-200 hover:border-brand-blue'}`}
                  >
                    <img 
                      src={img} 
                      alt={`${product.name} view ${index + 1}`} 
                      className="w-full h-full object-contain mix-blend-multiply" 
                    />
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* RIGHT SIDE: Details */}
          <div className="w-full lg:w-1/2">
            <h1 className="text-3xl md:text-4xl font-bold text-brand-blue mb-2">
              {language === 'hi' && product.name_hi ? product.name_hi : product.name}
            </h1>
            <div className="h-1 w-20 bg-brand-yellow mb-6"></div>

            <p className="text-gray-600 mb-8 text-lg leading-relaxed">
              {language === 'hi' && product.description_hi ? product.description_hi : product.description}
            </p>

            {/* Product Specifications Table */}
            <div className="bg-white border rounded-lg overflow-hidden shadow-sm mb-8">
              <div className="bg-brand-blue px-6 py-3">
                <h3 className="text-white font-semibold">{t('product.specs')}</h3>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left text-sm">
                  <thead>
                    <tr className="bg-gray-100 border-b border-gray-200">
                      {product.variants.length > 1 && <th className="px-4 py-3 font-semibold text-gray-700">{t('product.variant')}</th>}
                      <th className="px-4 py-3 font-semibold text-gray-700">{t('product.itemCode')}</th>
                      <th className="px-4 py-3 font-semibold text-gray-700">{t('product.size')}</th>
                      <th className="px-4 py-3 font-semibold text-gray-700">{t('product.dim')}</th>
                      <th className="px-4 py-3 font-semibold text-gray-700">{t('product.thickness')}</th>
                      <th className="px-4 py-3 font-semibold text-gray-700">{t('product.weight')}</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {product.variants.map((variant, index) => (
                      <tr key={index} className="hover:bg-gray-50 transition-colors">
                        {product.variants.length > 1 && (
                          <td className="px-4 py-4 font-medium text-brand-blue">{variant.variantName}</td>
                        )}
                        <td className="px-4 py-4 text-gray-600">{variant.itemCode || '-'}</td>
                        <td className="px-4 py-4 text-gray-900 font-semibold">{variant.size}</td>
                        <td className="px-4 py-4 text-gray-600">{variant.length} x {variant.width}</td>
                        <td className="px-4 py-4 text-gray-600">{variant.thickness}</td>
                        <td className="px-4 py-4 text-gray-600">{variant.weight}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            <div className="flex gap-4">
               <Link to="/contact" className="flex-1 bg-brand-blue text-white text-center py-3 rounded-md font-medium hover:bg-gray-900 transition-colors shadow-md">
                 {t('product.enquire')}
               </Link>
               <button className="flex items-center justify-center w-12 h-12 border border-gray-300 rounded-md hover:bg-gray-50 text-gray-600 hover:text-brand-blue">
                 <Share2 size={20} />
               </button>
               <button className="flex items-center justify-center w-12 h-12 border border-gray-300 rounded-md hover:bg-gray-50 text-gray-600 hover:text-brand-blue">
                 <Download size={20} />
               </button>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetail;

